MATCH (func:OPERATIONS {name: "hl.func"})
WHERE func.func_name CONTAINS "config_input"
RETURN func.uid, func.func_name, func.fs_raw_name, func.location;

MATCH (:OPERATIONS {uid: 2525})-[:CHILDREGION]->()-[:CHILDBLOCK]->()-[:CHILDINST]->(child:OPERATIONS)
RETURN child.uid, child.name, child.location
LIMIT 100;

MATCH (:OPERATIONS {uid: 2530})-[:CHILDREGION]->()-[:CHILDBLOCK]->()-[:CHILDINST]->(child:OPERATIONS)
RETURN child.uid, child.name, child.location
LIMIT 100;

MATCH (:OPERATIONS {uid: 351})-[:CHILDREGION]->()-[:CHILDBLOCK]->()-[:CHILDINST]->(child:OPERATIONS)
WHERE child.name IN ["hl.call"]
CALL {
  WITH child
  MATCH (child)-[:ARGATTR {idx: 0}]->(s:STRINGATTRS)
  RETURN s.value AS func_name
}
RETURN child.uid, child.location, func_name;

